import { CLOUDINARY_CLOUD_NAME, CLOUDINARY_UPLOAD_PRESET } from '../constants';

export interface UploadResult {
  url: string;
  publicId: string;
  type: 'image' | 'video';
}

export const uploadMedia = async (file: File): Promise<UploadResult> => {
  const formData = new FormData();
  formData.append('file', file);
  formData.append('upload_preset', CLOUDINARY_UPLOAD_PRESET);

  // 'auto' allows Cloudinary to detect if it is an image or a video
  const resourceType = 'auto'; 

  try {
    const response = await fetch(
      `https://api.cloudinary.com/v1_1/${CLOUDINARY_CLOUD_NAME}/${resourceType}/upload`,
      {
        method: 'POST',
        body: formData,
      }
    );

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.error?.message || 'Upload failed');
    }

    const data = await response.json();
    return {
      url: data.secure_url,
      publicId: data.public_id,
      type: data.resource_type === 'video' ? 'video' : 'image'
    };
  } catch (error) {
    console.error('Error uploading media:', error);
    throw error;
  }
};

// Note: Deleting from Cloudinary requires a signed request from a backend server 
// or an Admin API call, which cannot be securely done from a client-side app 
// without exposing the API Secret.
// For this architecture, we will simply remove the reference from Firestore.

import React, { useState } from 'react';
import { Upload, Loader, Check, Film, Image as ImageIcon } from 'lucide-react';
import { uploadMedia, UploadResult } from '../services/mediaService';

interface ImageUploaderProps {
  onUploadComplete: (result: UploadResult) => void;
  label?: string;
  accept?: string;
}

export const ImageUploader: React.FC<ImageUploaderProps> = ({ 
  onUploadComplete, 
  label = "Upload Media",
  accept = "image/*,video/*"
}) => {
  const [uploading, setUploading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Basic validation
    if (file.size > 100 * 1024 * 1024) { // 100MB limit
      setError("File is too large. Max 100MB.");
      return;
    }

    setUploading(true);
    setError(null);
    setSuccess(false);

    try {
      const result = await uploadMedia(file);
      onUploadComplete(result);
      setSuccess(true);
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) {
      setError("Failed to upload media. Please try again.");
    } finally {
      setUploading(false);
    }
  };

  return (
    <div className="mb-4">
      <label className="block text-sm font-medium text-slate-700 mb-2">{label}</label>
      <div className="flex flex-col gap-2">
        <label className={`
          flex items-center justify-center gap-2 px-4 py-6 
          bg-slate-50 text-slate-600 rounded-xl border-2 border-dashed border-slate-300 
          cursor-pointer hover:bg-slate-100 hover:border-teal-400 hover:text-teal-600 
          transition-all duration-200 group
          ${uploading ? 'opacity-75 cursor-not-allowed' : ''}
        `}>
          {uploading ? (
            <Loader className="animate-spin text-teal-600" size={24} />
          ) : (
            <div className="flex flex-col items-center gap-1">
              <Upload size={24} className="group-hover:-translate-y-1 transition-transform" />
            </div>
          )}
          <span className="font-bold text-sm">{uploading ? "Uploading to Cloud..." : "Click to Select File"}</span>
          <input 
            type="file" 
            className="hidden" 
            accept={accept} 
            onChange={handleFileChange} 
            disabled={uploading} 
          />
        </label>

        <div className="flex justify-between items-start text-xs text-slate-400 px-1">
          <span>Supports JPG, PNG, MP4, WebM</span>
          {success && <span className="text-teal-600 font-bold flex items-center gap-1"><Check size={12}/> Upload Complete</span>}
        </div>
      </div>
      {error && <p className="text-red-500 text-xs mt-2 bg-red-50 p-2 rounded">{error}</p>}
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { doc, onSnapshot, updateDoc, setDoc } from 'firebase/firestore';
import { db } from '../firebase';
import { DEFAULT_CONTENT, FIREBASE_CONFIG } from '../constants';
import { SiteContent, ContentContextType, Program } from '../types';

const ContentContext = createContext<ContentContextType | undefined>(undefined);

export const useContent = () => {
  const context = useContext(ContentContext);
  if (!context) throw new Error('useContent must be used within a ContentProvider');
  return context;
};

// Ensure defaults match the new types
const INITIAL_CONTENT: SiteContent = {
  ...DEFAULT_CONTENT,
  gallery: [
    {
      id: 'g1',
      url: 'https://picsum.photos/800/800?random=10',
      publicId: 'demo/1',
      type: 'image',
      category: 'General',
      createdAt: new Date().toISOString()
    },
    {
      id: 'g2',
      url: 'https://picsum.photos/800/800?random=11',
      publicId: 'demo/2',
      type: 'image',
      category: 'Education',
      createdAt: new Date().toISOString()
    },
    {
      id: 'g3',
      url: 'https://picsum.photos/800/800?random=12',
      publicId: 'demo/3',
      type: 'image',
      category: 'Community',
      createdAt: new Date().toISOString()
    }
  ]
};

export const ContentProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [content, setContent] = useState<SiteContent>(INITIAL_CONTENT);
  const [loading, setLoading] = useState(true);

  // Check if we are using the placeholder API key.
  const isDemoMode = !FIREBASE_CONFIG.apiKey || FIREBASE_CONFIG.apiKey === "YOUR_API_KEY_HERE";

  useEffect(() => {
    if (isDemoMode) {
      console.log("⚠️ No valid Firebase configuration detected. Running in Offline/Demo Mode using LocalStorage.");
      const localData = localStorage.getItem('mati_content');
      if (localData) {
        try {
          setContent(JSON.parse(localData));
        } catch (e) {
          console.error("Error parsing local content", e);
        }
      }
      setLoading(false);
      return;
    }

    // Real Firebase connection
    const docRef = doc(db, 'website_content', 'main_v1');

    const unsubscribe = onSnapshot(docRef, (docSnap) => {
      if (docSnap.exists()) {
        const data = docSnap.data() as any;
        // Migration helper: If gallery is old string[], convert to MediaItem[] locally to prevent crash
        if (Array.isArray(data.gallery) && typeof data.gallery[0] === 'string') {
           data.gallery = data.gallery.map((url: string, i: number) => ({
             id: `legacy-${i}`,
             url,
             publicId: 'legacy',
             type: 'image',
             category: 'General',
             createdAt: new Date().toISOString()
           }));
        }
        setContent(data as SiteContent);
      } else {
        console.log("Document does not exist in Firestore. Using defaults.");
        // Initialize DB with defaults if needed
        // setDoc(docRef, INITIAL_CONTENT);
      }
      setLoading(false);
    }, (error) => {
      console.warn("Firestore connection issue (falling back to offline mode):", error.message);
      setLoading(false);
    });

    return () => unsubscribe();
  }, [isDemoMode]);

  const updateContent = async (section: keyof SiteContent, data: any) => {
    const newContent = { ...content, [section]: data };

    // Optimistic update for UI
    setContent(newContent);

    if (isDemoMode) {
      localStorage.setItem('mati_content', JSON.stringify(newContent));
      return;
    }

    try {
        const docRef = doc(db, 'website_content', 'main_v1');
        await updateDoc(docRef, { [section]: data });
    } catch (e: any) {
        if (e.code === 'not-found') {
           const docRef = doc(db, 'website_content', 'main_v1');
           await setDoc(docRef, { [section]: data }, { merge: true });
        } else {
           console.error("Failed to update content in Firestore", e);
           alert("Changes saved locally only (Database connection failed).");
        }
    }
  };

  const updateProgram = async (updatedProgram: Program) => {
    const newPrograms = content.programs.map(p => p.id === updatedProgram.id ? updatedProgram : p);
    await updateContent('programs', newPrograms);
  };

  const addProgram = async (program: Program) => {
    const newPrograms = [...content.programs, program];
    await updateContent('programs', newPrograms);
  };

  const deleteProgram = async (id: string) => {
    const newPrograms = content.programs.filter(p => p.id !== id);
    await updateContent('programs', newPrograms);
  };

  return (
    <ContentContext.Provider value={{ content, loading, updateContent, updateProgram, addProgram, deleteProgram }}>
      {children}
    </ContentContext.Provider>
  );
};

