                    <Route path="/get-involved" element={<GetInvolved />} />
                    <Route path="/stories" element={<Stories />} />
                    <Route path="/gallery" element={<Gallery />} />
                    <Route path="/contact" element={<Contact />} />
                    <Route path="*" element={<Navigate to="/" replace />} />
                  </Routes>
                </Layout>
              }
            />
          </Routes>
        </HashRouter>
      </ContentProvider>
    </AuthProvider>
  );
};

export default App;

