  Layout, Type, Image as ImageIcon, Users, Settings, LogOut, Save, 
  Plus, Trash2, Edit2, ExternalLink, Heart, BookOpen, Video, Film, Menu, X, Check, ChevronLeft, Play
} from 'lucide-react';
